48	const createTextDecoder = (contentType: string): TextDecoder => {
49		const match = /;\s*charset\s*=\s*(?:"([^"]+)"|([^;,\s]+))/i.exec(contentType);
50		const charset = match?.[1] ?? match?.[2];
51		if (charset) {
52			try {
53				return new TextDecoder(charset);
54			} catch {}
55		}
56	
57		return new TextDecoder();
58	};
