62	const cloneRetryOptions = (retry: RetryOptions | number): RetryOptions | number => {
63		if (typeof retry !== 'object') {
64			return retry;
65		}
66	
67		// Clone nested arrays too so init hooks can mutate retry config without leaking state across requests.
68		return {
69			...retry,
70			...(retry.methods && {methods: [...retry.methods]}),
71			...(retry.statusCodes && {statusCodes: [...retry.statusCodes]}),
72			...(retry.afterStatusCodes && {afterStatusCodes: [...retry.afterStatusCodes]}),
73		};
74	};
