81	// Accepted custom responses are treated as full Responses throughout Ky.
82	// If a custom fetch returns one, it must behave like a Response for cloning,
83	// body consumption, `json()` decoration, and any enabled stream features.
84	const isResponseInstance = (value: unknown): value is Response =>
85		value instanceof globalThis.Response || objectToString.call(value) === '[object Response]';
