87	const cloneSearchParametersForInitHook = (searchParameters: SearchParamsOption | undefined): SearchParamsOption | undefined => {
88		if (Array.isArray(searchParameters)) {
89			return searchParameters.map(parameter => [...parameter]) as SearchParamsOption;
90		}
91	
92		return cloneShallow(searchParameters) as SearchParamsOption | undefined;
93	};
