95	// Shallow-clone mutable option properties so init hook mutations don't leak across requests.
96	function cloneInitHookOptions(options: Options): Options {
97		const clonedOptions: Options = {
98			...options,
99			json: cloneShallow(options.json),
100			context: cloneShallow(options.context)!,
101			headers: cloneShallow(options.headers)!,
102			searchParams: cloneSearchParametersForInitHook(options.searchParams),
103		};
104	
105		if (options.retry !== undefined) {
106			clonedOptions.retry = cloneRetryOptions(options.retry);
107		}
108	
109		return clonedOptions;
110	}
