112	const validateJsonWithSchema = async (jsonValue: unknown, schema: StandardSchemaV1): Promise<unknown> => {
113		if (
114			(
115				typeof schema !== 'object'
116				&& typeof schema !== 'function'
117			)
118			|| schema === null
119		) {
120			throw new TypeError(invalidSchemaMessage);
121		}
122	
123		const standardSchema = schema['~standard'];
124	
125		if (
126			typeof standardSchema !== 'object'
127			|| standardSchema === null
128			|| typeof standardSchema.validate !== 'function'
129		) {
130			throw new TypeError(invalidSchemaMessage);
131		}
132	
133		const validationResult = await standardSchema.validate(jsonValue);
134	
135		if (validationResult.issues) {
136			throw new SchemaValidationError(validationResult.issues);
137		}
138	
139		return validationResult.value;
140	};
