142	export class Ky {
143		static create(input: Input, options: Options): ResponsePromise {
144			const initHooks = options.hooks?.init ?? [];
145			const initHookOptions = initHooks.length > 0 ? cloneInitHookOptions(options) : options;
146	
147			for (const hook of initHooks) {
148				hook(initHookOptions);
149			}
150	
151			const ky = new Ky(input, initHookOptions);
152	
153			const function_ = async (): Promise<Response | void> => {
154				if (typeof ky.#options.timeout === 'number' && ky.#options.timeout > maxSafeTimeout) {
155					throw new RangeError(`The \`timeout\` option cannot be greater than ${maxSafeTimeout}`);
156				}
157	
158				if (typeof ky.#options.totalTimeout === 'number' && ky.#options.totalTimeout > maxSafeTimeout) {
159					throw new RangeError(`The \`totalTimeout\` option cannot be greater than ${maxSafeTimeout}`);
160				}
161	
162				// Delay the fetch so that body method shortcuts can set the Accept header
163				await Promise.resolve();
164				const beforeRequestResponse = await ky.#runBeforeRequestHooks();
165				let response = beforeRequestResponse ?? await ky.#retry(async () => ky.#fetch());
166				let responseFromHook = beforeRequestResponse !== undefined
167					|| ky.#consumeReturnedResponseFromBeforeRetryHook();
168	
169				for (;;) {
170					// `undefined` means a hook stopped the flow without providing a response.
171					// Non-native Responses still continue through Ky if they pass `isResponseInstance()`.
172					if (response === undefined) {
173						return response;
174					}
175	
176					if (isResponseInstance(response)) {
177						try {
178							// eslint-disable-next-line no-await-in-loop
179							response = await ky.#runAfterResponseHooks(response);
180						} catch (error) {
181							if (!(error instanceof ForceRetryError)) {
182								throw error;
183							}
184	
185							// eslint-disable-next-line no-await-in-loop
186							const retriedResponse: Response | void = await ky.#retryFromError(error, async () => ky.#fetch());
187							if (retriedResponse === undefined) {
188								return retriedResponse;
189							}
190	
191							response = retriedResponse;
192							responseFromHook = ky.#consumeReturnedResponseFromBeforeRetryHook();
193							continue;
194						}
195					}
196	
197					const currentResponse: Response = response;
198	
199					// Opaque responses (`response.type === 'opaque'`) from `no-cors` requests always have `status: 0` and `ok: false`, but this is not a failure - the actual status is hidden by the browser.
200					if (!currentResponse.ok && currentResponse.type !== 'opaque' && (
201						typeof ky.#options.throwHttpErrors === 'function'
202							? ky.#options.throwHttpErrors(currentResponse.status)
203							: ky.#options.throwHttpErrors
204					)) {
205						// `request` must reflect the request that actually failed, but `options` stays as Ky's
206						// normalized options snapshot. Replacement `Request` instances do not preserve the
207						// original `BodyInit`, so trying to make `options` mirror arbitrary requests would be lossy.
208						const httpError: HTTPError = new HTTPError(currentResponse, ky.#getResponseRequest(currentResponse), ky.#getNormalizedOptions());
209						const errorToThrow: Error = httpError;
210						// eslint-disable-next-line no-await-in-loop
211						httpError.data = await ky.#getResponseData(currentResponse);
212	
213						if (responseFromHook) {
214							throw errorToThrow;
215						}
216	
217						// eslint-disable-next-line no-await-in-loop
218						const retriedResponse: Response | void = await ky.#retryFromError(httpError, async () => ky.#fetch());
219						if (retriedResponse === undefined) {
220							return retriedResponse;
221						}
222	
223						response = retriedResponse;
224						responseFromHook = ky.#consumeReturnedResponseFromBeforeRetryHook();
225						continue;
226					}
227	
228					break;
229				}
230	
231				if (!isResponseInstance(response)) {
232					return response;
233				}
234	
235				ky.#decorateResponse(response);
236	
237				// If `onDownloadProgress` is passed, it uses the stream API internally
238				if (ky.#options.onDownloadProgress) {
239					if (typeof ky.#options.onDownloadProgress !== 'function') {
240						throw new TypeError('The `onDownloadProgress` option must be a function');
241					}
242	
243					if (!supportsResponseStreams) {
244						throw new Error('Streams are not supported in your environment. `ReadableStream` is missing.');
245					}
246	
247					const progressResponse = response.clone();
248					ky.#cancelResponseBody(response);
249					return streamResponse(progressResponse, ky.#options.onDownloadProgress);
250				}
251	
252				return response;
253			};
254	
255			const result = (async () => {
256				try {
257					return await function_();
258				} catch (error: unknown) {
259					// Non-Error throws (e.g., thrown strings) pass through unchanged
260					if (!(error instanceof Error)) {
261						throw error;
262					}
263	
264					// Errors thrown by beforeRetry hooks must propagate unchanged.
265					if (ky.#beforeRetryHookErrors.has(error)) {
266						throw error;
267					}
268	
269					let processedError: Error = error;
270					for (const hook of ky.#options.hooks.beforeError) {
271						// `request` is the current failing request. `options` intentionally remains the
272						// stable normalized Ky options snapshot for the same reason as `HTTPError` above.
273						// eslint-disable-next-line no-await-in-loop
274						const hookResult: unknown = await hook({
275							request: ky.request,
276							options: ky.#getNormalizedOptions(),
277							error: processedError,
278							retryCount: ky.#retryCount,
279						});
280	
281						// Only overwrite if the hook returns a valid Error instance.
282						if (hookResult instanceof Error) {
283							processedError = hookResult;
284						}
285					}
286	
287					throw processedError;
288				} finally {
289					const originalRequest = ky.#originalRequest;
290	
291					// Ignore cancellation errors from already-locked or already-consumed streams.
292					ky.#cancelBody(originalRequest?.body ?? undefined);
293					// Only cancel the current request body if it's distinct from the original (i.e. it was cloned for retries).
294					if (ky.request !== originalRequest) {
295						ky.#cancelBody(ky.request.body ?? undefined);
296					}
297				}
298			})() as ResponsePromise;
299	
300			for (const [type, mimeType] of Object.entries(responseTypes) as ObjectEntries<typeof responseTypes>) {
301				// Only expose `.bytes()` when the environment implements it.
302				if (
303					type === 'bytes'
304					&& typeof (globalThis.Response?.prototype as unknown as {bytes?: unknown})?.bytes !== 'function'
305				) {
306					continue;
307				}
308	
309				result[type] = async (schema?: StandardSchemaV1) => {
310					// eslint-disable-next-line @typescript-eslint/prefer-nullish-coalescing
311					ky.request.headers.set('accept', ky.request.headers.get('accept') || mimeType);
312	
313					const response = await result;
314	
315					if (type !== 'json') {
316						return response[type]();
317					}
318	
319					const text = await response.text();
320					if (text === '') {
321						if (schema !== undefined) {
322							return validateJsonWithSchema(undefined, schema);
323						}
324	
325						return JSON.parse(text);
326					}
327	
328					const jsonValue = initHookOptions.parseJson
329						? await initHookOptions.parseJson(text, {request: ky.#getResponseRequest(response), response})
330						: JSON.parse(text);
331	
332					return schema === undefined ? jsonValue : validateJsonWithSchema(jsonValue, schema);
333				};
334			}
335	
336			return result;
337		}
