339		// eslint-disable-next-line unicorn/prevent-abbreviations
340		static #normalizeSearchParams(searchParams: SearchParamsOption): SearchParamsOption {
341			// Filter out undefined values from plain objects
342			if (searchParams && typeof searchParams === 'object' && !Array.isArray(searchParams) && !(searchParams instanceof URLSearchParams)) {
343				return Object.fromEntries(Object.entries(searchParams).filter(([, value]) => value !== undefined));
344			}
345	
346			return searchParams;
347		}
