349		public request: Request;
350		#abortController?: AbortController;
351		#retryCount = 0;
352		// eslint-disable-next-line @typescript-eslint/prefer-readonly -- False positive: #input is reassigned on line 202
353		#input: Input;
354		readonly #options: InternalOptions;
355		#originalRequest?: Request;
356		readonly #userProvidedAbortSignal?: AbortSignal;
357		readonly #beforeRetryHookErrors = new WeakSet<Error>();
358		#cachedNormalizedOptions: NormalizedOptions | undefined;
359		readonly #startTime: number | undefined;
360		#returnedResponseFromBeforeRetryHook = false;
361		readonly #responseRequests = new WeakMap<Response, Request>();
