363		// eslint-disable-next-line complexity
364		constructor(input: Input, options: Options = {}) {
365			this.#input = input;
366			if (Object.hasOwn(options, 'prefixUrl')) {
367				throw new Error(prefixUrlRenamedErrorMessage);
368			}
369	
370			this.#options = {
371				...options,
372				headers: mergeHeaders((this.#input as Request).headers, options.headers),
373				hooks: mergeHooks({}, options.hooks),
374				method: normalizeRequestMethod(options.method ?? (this.#input as Request).method ?? 'GET'),
375				// eslint-disable-next-line @typescript-eslint/prefer-nullish-coalescing
376				prefix: String(options.prefix || ''),
377				retry: normalizeRetryOptions(options.retry),
378				throwHttpErrors: options.throwHttpErrors ?? true,
379				timeout: options.timeout ?? 10_000,
380				totalTimeout: options.totalTimeout ?? false,
381				fetch: options.fetch ?? globalThis.fetch.bind(globalThis),
382				context: options.context ?? {},
383			};
384	
385			if (typeof this.#input !== 'string' && !(this.#input instanceof URL || this.#input instanceof globalThis.Request)) {
386				throw new TypeError('`input` must be a string, URL, or Request');
387			}
388	
389			if (typeof this.#input === 'string') {
390				if (this.#options.prefix) {
391					const normalizedPrefix = this.#options.prefix.replace(/\/+$/, '');
392					const normalizedInput = this.#input.replace(/^\/+/, '');
393					this.#input = `${normalizedPrefix}/${normalizedInput}`;
394				}
395	
396				if (this.#options.baseUrl) {
397					let absoluteInput: URL | undefined;
398					try {
399						absoluteInput = new URL(this.#input);
400					} catch {}
401	
402					if (!absoluteInput) {
403						this.#input = new URL(this.#input, (new Request(this.#options.baseUrl)).url);
404					}
405				}
406			}
407	
408			if (supportsAbortController && supportsAbortSignal) {
409				this.#userProvidedAbortSignal = this.#options.signal ?? (this.#input as Request).signal;
410				this.#abortController = new globalThis.AbortController();
411				this.#options.signal = this.#createManagedSignal();
412			}
413	
414			if (supportsRequestStreams) {
415				// @ts-expect-error - Types are outdated.
416				this.#options.duplex = 'half';
417			}
418	
419			if (this.#options.json !== undefined) {
420				this.#options.body = this.#options.stringifyJson?.(this.#options.json) ?? JSON.stringify(this.#options.json);
421				this.#options.headers.set('content-type', this.#options.headers.get('content-type') ?? 'application/json');
422			}
423	
424			// To provide correct form boundary, Content-Type header should be deleted when creating Request from another Request with FormData/URLSearchParams body
