426			const userProvidedContentType = options.headers && new globalThis.Headers(options.headers as HeadersInit).has('content-type');
427			if (
428				this.#input instanceof globalThis.Request
429				&& ((supportsFormData && this.#options.body instanceof globalThis.FormData) || this.#options.body instanceof URLSearchParams)
430				&& !userProvidedContentType
431			) {
432				this.#options.headers.delete('content-type');
433			}
434	
435			this.request = new globalThis.Request(this.#input, this.#options);
436	
437			if (hasSearchParameters(this.#options.searchParams)) {
438				const url = new URL(this.request.url);
439				const deleted = (this.#options.searchParams as any)?.[deletedParametersSymbol] as Set<string> | undefined;
440	
441				if (deleted) {
442					// Remove keys from the input URL first so later searchParams entries can intentionally re-add them.
443					for (const key of deleted) {
444						url.searchParams.delete(key);
445					}
446				}
447	
448				if (typeof this.#options.searchParams === 'string') {
449					const stringSearchParameters = this.#options.searchParams.replace(/^\?/, '');
450					if (stringSearchParameters !== '') {
451						url.search = url.search ? `${url.search}&${stringSearchParameters}` : `?${stringSearchParameters}`;
452					}
453				} else {
454					const optionsSearchParameters = new URLSearchParams(Ky.#normalizeSearchParams(this.#options.searchParams) as unknown as SearchParamsInit);
455	
456					for (const [key, value] of optionsSearchParameters.entries()) {
457						url.searchParams.append(key, value);
458					}
459				}
460	
461				if (
462					this.#options.searchParams
463					&& typeof this.#options.searchParams === 'object'
464					&& !Array.isArray(this.#options.searchParams)
465					&& !(this.#options.searchParams instanceof URLSearchParams)
466				) {
467					for (const [key, value] of Object.entries(this.#options.searchParams)) {
468						if (value === undefined) {
469							url.searchParams.delete(key);
470						}
471					}
472				}
473	
474				// Recreate request with the updated URL. We already have all options in this.#options, including duplex.
475				this.request = new globalThis.Request(url, this.#options as RequestInit);
476			}
477	
478			if (this.#options.onUploadProgress && typeof this.#options.onUploadProgress !== 'function') {
479				throw new TypeError('The `onUploadProgress` option must be a function');
480			}
481	
482			// `totalTimeout` starts when the request pipeline is created, so it also includes
483			// Ky's internal scheduling and user hook time before the first fetch attempt.
484			this.#startTime = typeof this.#options.totalTimeout === 'number' ? this.#getCurrentTime() : undefined;
485		}
