487		#calculateDelay(): number {
488			const retryDelay = this.#options.retry.delay(this.#retryCount + 1);
489	
490			let jitteredDelay = retryDelay;
491			if (this.#options.retry.jitter === true) {
492				jitteredDelay = Math.random() * retryDelay;
493			} else if (typeof this.#options.retry.jitter === 'function') {
494				jitteredDelay = this.#options.retry.jitter(retryDelay);
495	
496				if (!Number.isFinite(jitteredDelay) || jitteredDelay < 0) {
497					jitteredDelay = retryDelay;
498				}
499			}
500	
501			return Math.min(this.#options.retry.backoffLimit, jitteredDelay);
502		}
503	
504		async #calculateRetryDelay(error: unknown) {
505			if (this.#retryCount >= this.#options.retry.limit) {
506				throw error;
507			}
508	
509			// Wrap non-Error throws to ensure consistent error handling
510			const errorObject = error instanceof Error ? error : new NonError(error);
511	
512			// Handle forced retry from afterResponse hook - skip method check and shouldRetry
513			if (errorObject instanceof ForceRetryError) {
514				return errorObject.customDelay ?? this.#calculateDelay();
515			}
516	
517			// Check if method is retriable for non-forced retries
518			if (!this.#options.retry.methods.includes(this.request.method.toLowerCase())) {
519				throw error;
520			}
521	
522			// User-provided shouldRetry function takes precedence over default checks (retryOnTimeout, status codes, etc.)
523			if (this.#options.retry.shouldRetry !== undefined) {
524				const result = await this.#options.retry.shouldRetry({error: errorObject, retryCount: this.#retryCount + 1});
525	
526				// Strict boolean checking - only exact true/false are handled specially
527				if (result === false) {
528					throw error;
529				}
530	
531				if (result === true) {
532					// Force retry - skip all other validation and return delay
533					return this.#calculateDelay();
534				}
535	
536				// If undefined or any other value, fall through to default behavior
537			}
538	
539			// Default timeout behavior
540			if (isTimeoutError(error)) {
541				if (!this.#options.retry.retryOnTimeout) {
542					throw error;
543				}
544	
545				return this.#calculateDelay();
546			}
547	
548			if (isHTTPError(error)) {
549				if (!this.#options.retry.statusCodes.includes(error.response.status)) {
550					throw error;
551				}
552	
553				const retryAfter = error.response.headers.get('Retry-After')
554					?? error.response.headers.get('RateLimit-Reset')
555					?? error.response.headers.get('X-RateLimit-Retry-After') // Symfony-based services
556					?? error.response.headers.get('X-RateLimit-Reset') // GitHub
557					?? error.response.headers.get('X-Rate-Limit-Reset'); // Twitter
558				if (retryAfter && this.#options.retry.afterStatusCodes.includes(error.response.status)) {
559					let after = Number(retryAfter) * 1000;
560					if (Number.isNaN(after)) {
561						after = Date.parse(retryAfter) - Date.now();
562					} else if (after >= Date.parse('2024-01-01')) {
563						// A large number is treated as a timestamp (fixed threshold protects against clock skew)
564						after -= Date.now();
565					}
566	
567					if (!Number.isFinite(after)) {
568						return Math.min(this.#options.retry.maxRetryAfter, this.#calculateDelay());
569					}
570	
571					after = Math.max(0, after);
572	
573					// Don't apply jitter when server provides explicit retry timing
574					return Math.min(this.#options.retry.maxRetryAfter, after);
575				}
576	
577				if (error.response.status === 413) {
578					throw error;
579				}
580	
581				return this.#calculateDelay();
582			}
583	
584			// Only retry known retriable error types. Unknown errors (e.g., programming bugs) are not retried.
585			if (!isNetworkError(error)) {
586				throw error;
587			}
588	
589			return this.#calculateDelay();
590		}
