592		#decorateResponse(response: Response): Response {
593			const request = this.#getResponseRequest(response);
594	
595			if (this.#options.parseJson) {
596				response.json = async () => {
597					const text = await response.text();
598					if (text === '') {
599						return JSON.parse(text);
600					}
601	
602					return this.#options.parseJson!(text, {request, response});
603				};
604			}
605	
606			return response;
607		}
